import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import './ProductDetail.css';
import axios from 'axios';
import Footer from '../components/Footer'; // ✅ Footer import (folder path check pannu)

function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [relatedProducts, setRelatedProducts] = useState([]);
  const [pincode, setPincode] = useState("");
  const [pincodeMessage, setPincodeMessage] = useState("");

  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}`)
      .then((res) => {
        setProduct(res.data);

        // ✅ Related products fetch by category
        axios.get(`http://localhost:5000/api/products?category=${res.data.category}`)
          .then((relatedRes) => {
            setRelatedProducts(
              relatedRes.data.filter(p => p._id !== res.data._id) // exclude same product
            );
          });
      })
      .catch((err) => {
        console.error("Error fetching product details:", err);
      });
  }, [id]);

  const handleAddToCart = () => {
    alert("Added to Cart!");
  };

  const handleBuyNow = () => {
    alert("Proceeding to Buy Now...");
  };

  const checkPincode = () => {
    // Demo delivery check
    if (pincode.length === 6) {
      setPincodeMessage(`Delivery available to ${pincode} in 4-5 days.`);
    } else {
      setPincodeMessage("Please enter a valid 6-digit pincode.");
    }
  };

  if (!product) return <p>Loading...</p>;

  return (
    <>
      <div className="product-detail-container">
        {/* Product Images */}
        <div className="product-image-section">
          {product.images && product.images.length > 0 ? (
            product.images.map((img, index) => (
              <img key={index} src={img} alt={`${product.name} ${index + 1}`} />
            ))
          ) : (
            <img src={product.image} alt={product.name} />
          )}
        </div>

        {/* Product Info */}
        <div className="product-info-section">
          <h2>{product.name}</h2>
          <p className="price">₹{product.price}</p>
          <p className="size">Size: {product.size || "Free Size"}</p>
          <p className="description">{product.description || "No description available."}</p>

          {/* Pincode Check */}
          <div className="pincode-check">
            <input
              type="text"
              placeholder="Enter Pincode"
              value={pincode}
              onChange={(e) => setPincode(e.target.value)}
            />
            <button onClick={checkPincode}>Check</button>
          </div>
          {pincodeMessage && <p className="pincode-message">{pincodeMessage}</p>}

          {/* Buttons */}
          <div className="product-buttons">
            <button onClick={handleAddToCart} className="add-to-cart-btn">Add to Cart</button>
            <button onClick={handleBuyNow} className="buy-now-btn">Buy Now</button>
          </div>
        </div>
      </div>

      {/* Related Products */}
      <div className="related-products">
        <h3>Related Products</h3>
        <div className="related-product-list">
          {relatedProducts.map((item) => (
            <div
              key={item._id}
              className="related-product-card"
              onClick={() => navigate(`/product/${item._id}`)}
            >
              <img src={item.image} alt={item.name} />
              <p>{item.name}</p>
              <p>₹{item.price}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Footer */}
      <Footer />
    </>
  );
}

export default ProductDetail;
